import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { ArrowLeft, Calendar, Clock, MapPin, User, FileText, AlertCircle, Users } from 'lucide-react';
import { Badge } from '../../components/ui/badge';

interface Audiencia {
  id: number;
  numeroProcesso: string;
  dataAudiencia: string;
  horarioInicio: string;
  duracao: number;
  tipoAudiencia: string;
  formato: string;
  competencia: string;
  status: string;
  observacoes?: string;
  vara?: {
    id: number;
    nome: string;
    numero: string;
  };
  juiz?: {
    id: number;
    nome: string;
  };
  promotor?: {
    id: number;
    nome: string;
  };
}

interface Participante {
  id: number;
  pessoa: {
    id: number;
    nome: string;
  };
  tipo: string;
  intimado: boolean;
  observacoes?: string;
}

const AudienciasDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [audiencia, setAudiencia] = useState<Audiencia | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchAudiencia = async () => {
      try {
        const response = await axios.get(`/api/audiencias/${id}`);
        setAudiencia(response.data);
        setError(null);
      } catch (err) {
        setError('Erro ao carregar dados da audiência. Por favor, tente novamente.');
        console.error('Erro ao buscar audiência:', err);
      } finally {
        setLoading(false);
      }
    };

    if (id) {
      fetchAudiencia();
    }
  }, [id]);

  const handleDelete = async () => {
    if (!audiencia || !window.confirm('Tem certeza que deseja excluir esta audiência?')) {
      return;
    }

    try {
      await axios.delete(`/api/audiencias/${audiencia.id}`);
      navigate('/audiencias');
    } catch (err) {
      setError('Erro ao excluir audiência. Por favor, tente novamente.');
      console.error('Erro ao excluir audiência:', err);
    }
  };

  const formatarData = (data: string) => {
    return new Date(data + 'T00:00:00').toLocaleDateString('pt-BR');
  };

  const getStatusBadgeClass = (status: string) => {
    switch (status) {
      case 'DESIGNADA':
        return 'bg-blue-100 text-blue-800';
      case 'REALIZADA':
        return 'bg-green-100 text-green-800';
      case 'PARCIALMENTE_REALIZADA':
        return 'bg-yellow-100 text-yellow-800';
      case 'CANCELADA':
        return 'bg-red-100 text-red-800';
      case 'REDESIGNADA':
        return 'bg-orange-100 text-orange-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="text-lg text-gray-600">Carregando...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">
        {error}
      </div>
    );
  }

  if (!audiencia) {
    return (
      <div className="bg-yellow-100 border border-yellow-400 text-yellow-700 px-4 py-3 rounded mb-4">
        Audiência não encontrada.
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-6">
      <div className="bg-white shadow-lg rounded-lg overflow-hidden">
        <div className="bg-gray-50 px-6 py-4 border-b border-gray-200">
          <div className="flex justify-between items-center">
            <h1 className="text-2xl font-bold text-gray-900">Detalhes da Audiência</h1>
            <div className="flex space-x-2">
              <Link
                to={`/audiencias/editar/${audiencia.id}`}
                className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
              >
                Editar
              </Link>
              <button
                onClick={handleDelete}
                className="bg-red-600 hover:bg-red-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
              >
                Excluir
              </button>
              <Link
                to="/audiencias"
                className="bg-gray-500 hover:bg-gray-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline"
              >
                Voltar
              </Link>
            </div>
          </div>
        </div>

        <div className="px-6 py-4">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Informações da Audiência</h3>
              <div className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-500">Processo</label>
                  <p className="mt-1 text-sm text-gray-900 font-mono">{audiencia.numeroProcesso}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500">Data</label>
                  <p className="mt-1 text-sm text-gray-900">{formatarData(audiencia.dataAudiencia)}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500">Hora</label>
                  <p className="mt-1 text-sm text-gray-900">{audiencia.horarioInicio}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500">Status</label>
                  <span className={`mt-1 inline-flex px-2 py-1 text-xs leading-5 font-semibold rounded-full ${getStatusBadgeClass(audiencia.status)}`}>
                    {audiencia.status}
                  </span>
                </div>
              </div>
            </div>

            <div>
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Responsáveis</h3>
              <div className="space-y-3">
                <div>
                  <label className="block text-sm font-medium text-gray-500">Vara</label>
                  <p className="mt-1 text-sm text-gray-900">{audiencia.vara.nome}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500">Juiz</label>
                  <p className="mt-1 text-sm text-gray-900">{audiencia.juiz.nome}</p>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-500">Promotor</label>
                  <p className="mt-1 text-sm text-gray-900">{audiencia.promotor.nome}</p>
                </div>
              </div>
            </div>
          </div>

          {audiencia.observacoes && (
            <div className="mt-6">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Observações</h3>
              <div className="bg-gray-50 rounded-lg p-4">
                <p className="text-sm text-gray-700 whitespace-pre-wrap">{audiencia.observacoes}</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AudienciasDetail;
